### Add these two private methods to the class:

```java
private List<SpaceNodeTreeNode> buildFolderTree(String spaceId) {
    List<TreeNode<SpaceNodeVo>> fullTree = spaceNodeQueryManager.getSpaceNodeTree(spaceId);
    return filterAndConvertFolders(fullTree);
}

private List<SpaceNodeTreeNode> filterAndConvertFolders(List<TreeNode<SpaceNodeVo>> nodes) {
    if (nodes == null || nodes.isEmpty()) {
        return List.of();
    }
    List<SpaceNodeTreeNode> result = new ArrayList<>();
    for (TreeNode<SpaceNodeVo> node : nodes) {
        SpaceNodeVo data = node.getData();
        if (Objects.equals(data.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
            SpaceNodeTreeNode grpcNode = SpaceNodeTreeNode.newBuilder()
                    .setId(data.getId())
                    .setName(data.getName() != null ? data.getName() : "")
                    .setType(data.getType())
                    .setParentId(node.getParentId() != null ? node.getParentId() : 0L)
                    .setAppSpaceNodeId(data.getAppSpaceNodeId() != null ? data.getAppSpaceNodeId() : "")
                    .setDescription(data.getDescription() != null ? data.getDescription() : "")
                    .addAllChildren(childFolders)
                    .build();
            result.add(grpcNode);
        } else {
            List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
            result.addAll(childFolders);
        }
    }
    return result;
}
```

