695→    private List<SpaceNodeTreeNode> filterAndConvertFolders(List<TreeNode<SpaceNodeVo>> nodes) {
696→        if (nodes == null || nodes.isEmpty()) {
697→            return List.of();
698→        }
699→        List<SpaceNodeTreeNode> result = new ArrayList<>();
700→        for (TreeNode<SpaceNodeVo> node : nodes) {
701→            SpaceNodeVo data = node.getData();
702→            if (Objects.equals(data.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
703→                List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
704→                SpaceNodeTreeNode grpcNode = SpaceNodeTreeNode.newBuilder()
705→                        .setId(data.getId())
706→                        .setName(data.getName() != null ? data.getName() : "")
707→                        .setType(data.getType())
708→                        .setParentId(node.getParentId() != null ? node.getParentId() : 0L)
709→                        .setAppSpaceNodeId(data.getAppSpaceNodeId() != null ? data.getAppSpaceNodeId() : "")
710→                        .setDescription(data.getDescription() != null ? data.getDescription() : "")
711→                        .addAllChildren(childFolders)
712→                        .build();
713→                result.add(grpcNode);
714→            } else {
715→                List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
716→                result.addAll(childFolders);
717→            }
718→        }
719→        return result;
720→    }
